import{_ as o,o as t,c as a,ag as l}from"./chunks/framework.BZohXCq9.js";const i=JSON.parse('{"title":"VSCode SSH 远程开发教程","description":"","frontmatter":{"title":"VSCode SSH 远程开发教程","date":"2024-02-22T18:44:47.000Z","description":"","tags":["Tools","VSCode","SSH Remote"],"categories":["tools"]},"headers":[],"relativePath":"posts/vscode-ssh-remote-tutorial/index.md","filePath":"posts/vscode-ssh-remote-tutorial/index.md","lastUpdated":1773893360000}'),s={name:"posts/vscode-ssh-remote-tutorial/index.md"};function r(n,e,p,h,c,S){return t(),a("div",null,[...e[0]||(e[0]=[l('<h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>磨刀不误砍柴功，非软件行业的朋友可能也需要使用 ssh 远程登录服务器写代码，学习一下 VSCode 的 ssh 远程开发功能能给工作带来不少便利。</p><h2 id="安装-vscode" tabindex="-1">安装 VSCode <a class="header-anchor" href="#安装-vscode" aria-label="Permalink to &quot;安装 VSCode&quot;">​</a></h2><p>首先，你需要在本地计算机上安装 VSCode。你可以从<a href="https://code.visualstudio.com/" target="_blank" rel="noreferrer">VSCode 官方网站</a>下载适用于你的操作系统的安装程序，并按照提示进行安装。</p><h2 id="安装-remote-ssh-插件" tabindex="-1">安装 Remote - SSH 插件 <a class="header-anchor" href="#安装-remote-ssh-插件" aria-label="Permalink to &quot;安装 Remote - SSH 插件&quot;">​</a></h2><p>在 VSCode 中，你需要安装 Remote - SSH 插件，以便能够通过 SSH 远程连接到其他计算机进行开发。</p><ol><li>打开 VSCode。</li><li>点击左侧的扩展图标（四个方块组成的图标）。</li><li>在搜索框中输入&quot;Remote - SSH&quot;。</li><li>在搜索结果中找到&quot;Remote - SSH&quot;插件，并点击安装按钮。</li></ol><h2 id="配置-ssh-连接" tabindex="-1">配置 SSH 连接 <a class="header-anchor" href="#配置-ssh-连接" aria-label="Permalink to &quot;配置 SSH 连接&quot;">​</a></h2><p>在 VSCode 中配置 SSH 连接，以便能够连接到远程计算机。</p><ol><li><p>点击左下角的&quot;Remote Explorer&quot;图标（纸飞机图标）。</p></li><li><p>在 Remote Explorer 面板中，点击右上角的&quot;SSH Targets&quot;按钮。</p></li><li><p>在弹出的菜单中选择&quot;Add SSH Host&quot;。</p></li><li><p>在弹出的输入框中输入远程计算机的 SSH 连接信息，包括主机名、用户名和密码或私钥路径。</p><p>例如:</p><div class="language-input vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">input</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ssh user_name@host_domain:22 -A</span></span></code></pre></div><p><code>user_name</code> 替换成自己的用户名 <code>host_domain</code> 替换成连接的服务器的域名或 ip 这里 <code>22</code> 是 ssh 默认端口号，也可能是其他的端口号</p></li><li><p>点击&quot;Add&quot;按钮，保存 SSH 连接配置。</p></li></ol><h2 id="连接到远程计算机" tabindex="-1">连接到远程计算机 <a class="header-anchor" href="#连接到远程计算机" aria-label="Permalink to &quot;连接到远程计算机&quot;">​</a></h2><p>连接到远程计算机，开始通过 SSH 进行远程开发。</p><ol><li>在 Remote Explorer 面板中，找到你添加的 SSH 连接配置。</li><li>右键点击连接配置，选择&quot;Connect to Host&quot;。</li><li>如果你使用密码进行身份验证，输入密码并点击&quot;OK&quot;。</li><li>如果一切顺利，VSCode 将连接到远程计算机，并在编辑器中显示远程文件系统。</li></ol><h2 id="远程开发" tabindex="-1">远程开发 <a class="header-anchor" href="#远程开发" aria-label="Permalink to &quot;远程开发&quot;">​</a></h2><p>现在，你可以在 VSCode 中进行远程开发了。</p><ol><li>在远程文件系统中打开文件或文件夹。</li><li>在编辑器中进行代码编辑、调试和运行。</li><li>使用 VSCode 的其他功能进行开发，如版本控制、终端等。</li></ol><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><p>无</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p>无</p>',20)])])}const d=o(s,[["render",r]]),m=Object.freeze(Object.defineProperty({__proto__:null,__pageData:i,default:d},Symbol.toStringTag,{value:"Module"}));export{m as _,i as __pageData,d as default};
